5	};
6	
7	const PROCESSING_FEE = 5;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_YEARS_THRESHOLD = 2;
13	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	const COMPONENT_BASE = 25;
16	const COMPONENT_BLOCK_BASE = 60;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const ITEM_BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	function componentBaseFor(count: number): number {
26	  return count === COMPONENT_BLOCK_SIZE
27	    ? COMPONENT_BLOCK_BASE
28	    : count * COMPONENT_BASE;
29	}
30	
31	function policyBase(items: Item[]): number {
32	  const componentCounts: Record<string, number> = {};
33	  let base = 0;
34	  for (const item of items) {
35	    if (COMPONENT_TYPES.has(item.type)) {
36	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
37	    } else {
38	      base += ITEM_BASE_PREMIUM[item.type];
39	    }
40	  }
41	  for (const count of Object.values(componentCounts)) {
42	    base += componentBaseFor(count);
43	  }
44	  return base;
45	}
46	
47	function surchargeOn(
48	  items: Item[],
49	  rate: number,
50	  applies: (item: Item) => boolean,
51	): number {
52	  let total = 0;
53	  for (const item of items) {
54	    if (applies(item)) {
55	      total += ITEM_BASE_PREMIUM[item.type] * rate;
56	    }
57	  }
58	  return total;
59	}
60	
61	const isCursed = (item: Item): boolean => item.cursed === true;
62	const isHighlyEnchanted = (item: Item): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	function quotePremium(
66	  customer: { yearsWithMHPCO: number },
67	  items: Item[],
68	  quoteIndex: number,
69	): number {
70	  const base = policyBase(items);
71	  // First-insurance is +10% on the base; use integer tenths to avoid float drift.
72	  const withFirstInsurance = (base * 11) / 10;
73	  const surcharges =
74	    surchargeOn(items, CURSE_SURCHARGE_RATE, isCursed) +
75	    surchargeOn(items, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted);
76	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
77	    ? base * LOYALTY_DISCOUNT_RATE
78	    : 0;
79	  const followUpDiscount = quoteIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
80	  const discounts = loyaltyDiscount + followUpDiscount;
81	  return Math.ceil(withFirstInsurance + surcharges - discounts) + PROCESSING_FEE;
82	}
83	
84	export function runScenario(input: unknown): unknown {
85	  const { customer, steps } = input as ScenarioInput;
86	  const results = steps.map(({ items }, index) => ({
87	    premium: quotePremium(customer, items, index),
88	  }));
89	  return { results };
90	}
